try {
  const rawResponse = $input.item.json.content[0].text;
  const extractedData = JSON.parse(rawResponse);
  const webhookData = $node["Webhook"].json.body;
  const matterId = webhookData.matterId || "1769228281";
  const clientEmail = webhookData.clientEmail || "client@example.com";
  const month = new Date().getMonth() + 1;
  const bookingType = (month >= 3 && month <= 8) ? "Office" : "Virtual";
  const bookingLink = (bookingType === "Office") ? "https://calendly.com/swans-santiago-p/summer-spring" : "https://calendly.com/swans-santiago-p/winter-autumn";
  return {
    json: {
      ...extractedData,
      matterId,
      clientEmail,
      bookingType,
      bookingLink
    }
  };
} catch (e) {
  throw new Error('Failed to parse AI response: ' + e.message);
}
